INSERT INTO form_definitions (id, form_id, version, schema, published_at, created_at, updated_at) VALUES
('d4a0cfb3-c943-4ed9-91a7-3ba7267293b7', 'primary-school-textbook-grant', '1.0.0', '{"formId":"primary-school-textbook-grant","title":"Get a Primary School Textbook Grant","description":"Each year, every child is entitled to a BDS $100 textbook grant while they are a student at a public or private primary school.","version":"1.0.0","createdAt":"2026-05-21T00:00:00Z","updatedAt":"2026-05-21T00:00:00Z","steps":[{"stepId":"child-details","title":"Tell us about the child","description":"You can add information for other children later.","elements":[{"ref":"components/first-name","overrides":{"fieldId":"child-first-name","validations":{"required":{"value":true,"error":"First name is required"},"minLength":{"value":2,"error":"First name must be at least 2 characters"}}}},{"ref":"components/last-name","overrides":{"fieldId":"child-last-name","validations":{"required":{"value":true,"error":"Last name is required"},"minLength":{"value":2,"error":"Last name must be at least 2 characters"}}}},{"ref":"components/national-id-number","overrides":{"fieldId":"child-id-number","label":"National Identification (ID) Number","validations":{"required":{"value":true,"error":"ID number is required"}}}},{"ref":"components/generic/show-hide","overrides":{"fieldId":"child-passport-toggle","label":"Use passport number instead","hint":"If you don''t have a National ID number, you can use your passport number instead."}},{"ref":"components/passport-number","overrides":{"fieldId":"child-passport-number","label":"Passport Number","behaviours":[{"type":"fieldConditionalOn","targetFieldId":"child-passport-toggle","operator":"equal","value":true}],"validations":{"required":{"value":true,"error":"Passport number is required"},"minLength":{"value":6,"error":"Passport number must be at least 6 characters"}}}},{"ref":"components/sex","overrides":{"fieldId":"child-sex","validations":{"required":{"value":true,"error":"Please select the child''s sex"}}}},{"ref":"components/name","overrides":{"fieldId":"child-school","label":"Name of institution","validations":{"required":{"value":true,"error":"Please enter the child''s school"}}}},{"ref":"components/name","overrides":{"fieldId":"child-principal-name","label":"Name of principal","validations":{"required":{"value":true,"error":"Principal''s name is required"}}}},{"ref":"components/name","overrides":{"fieldId":"child-class-number","label":"Which class are they currently in?","hint":"If they are between school years, add the class they are going into","validations":{"required":{"value":true,"error":"Class number is required"}}}},{"ref":"components/generic/radio","overrides":{"fieldId":"is-parent-or-guardian","label":"Are you the parent or guardian?","options":[{"label":"Yes","value":"yes"},{"label":"No","value":"no"}],"validations":{"required":{"value":true,"error":"Relationship is required"}}}},{"ref":"components/name","overrides":{"fieldId":"relationship-description","label":"What is your relationship with the child?","behaviours":[{"type":"fieldConditionalOn","targetFieldId":"is-parent-or-guardian","operator":"equal","value":"no"}],"validations":{"required":{"value":true,"error":"Please describe your relationship"}}}}]},{"stepId":"applicant-details","title":"Tell us about yourself","elements":[{"ref":"components/first-name","overrides":{"fieldId":"applicant-first-name","validations":{"required":{"value":true,"error":"First name is required"},"minLength":{"value":2,"error":"First name must be at least 2 characters"}}}},{"ref":"components/last-name","overrides":{"fieldId":"applicant-last-name","validations":{"required":{"value":true,"error":"Last name is required"},"minLength":{"value":2,"error":"Last name must be at least 2 characters"}}}},{"ref":"components/address","overrides":{"fieldId":"applicant-address-1","label":"Address line 1","validations":{"required":{"value":true,"error":"Address line 1 is required"},"minLength":{"value":5,"error":"Address must be at least 5 characters"}}}},{"ref":"components/address","overrides":{"fieldId":"applicant-address-2","label":"Address line 2"}},{"ref":"components/parish","overrides":{"fieldId":"applicant-parish","options":[{"label":"Christ Church","value":"christ-church"},{"label":"St. Andrew","value":"st-andrew"},{"label":"St. George","value":"st-george"},{"label":"St. James","value":"st-james"},{"label":"St. John","value":"st-john"},{"label":"St. Joseph","value":"st-joseph"},{"label":"St. Lucy","value":"st-lucy"},{"label":"St. Michael","value":"st-michael"},{"label":"St. Peter","value":"st-peter"},{"label":"St. Philip","value":"st-philip"},{"label":"St. Thomas","value":"st-thomas"}],"validations":{"required":{"value":true,"error":"Parish is required"}}}},{"ref":"components/postcode","overrides":{"fieldId":"applicant-postcode","hint":"For example, BB17004 (optional)"}},{"ref":"components/email","overrides":{"fieldId":"applicant-email","validations":{"required":{"value":true,"error":"Email address is required"}}}},{"ref":"components/telephone","overrides":{"fieldId":"applicant-telephone","validations":{"required":{"value":true,"error":"Telephone number is required"}}}},{"ref":"components/national-id-number","overrides":{"fieldId":"applicant-id-number","label":"National Identification (ID) Number","validations":{"required":{"value":true,"error":"ID Number is required"}}}},{"ref":"components/generic/show-hide","overrides":{"fieldId":"applicant-passport-toggle","label":"Use passport number instead","hint":"If you don''t have a National ID number, you can use your passport number instead."}},{"ref":"components/passport-number","overrides":{"fieldId":"applicant-passport-number","label":"Passport Number","behaviours":[{"type":"fieldConditionalOn","targetFieldId":"applicant-passport-toggle","operator":"equal","value":true}],"validations":{"required":{"value":true,"error":"Passport number is required"},"minLength":{"value":6,"error":"Passport number must be at least 6 characters"}}}},{"ref":"components/tamis-number","overrides":{"fieldId":"applicant-tamis-number","validations":{"required":{"value":true,"error":"TAMIS number is required"}}}}]},{"stepId":"bank-account","title":"Bank account information","description":"Add the bank account details for an account which has been used within the last 3 months. Check your details are correct to avoid delays.","elements":[{"ref":"components/account-name","overrides":{"fieldId":"bank-account-holder-name","label":"Account holder name","hint":"Enter the full name shown on the bank account","validations":{"required":{"value":true,"error":"Name on account is required"},"minLength":{"value":2,"error":"Name must be at least 2 characters"}}}},{"ref":"components/bank","overrides":{"fieldId":"bank-name","label":"Bank name","hint":"For example: Republic Bank, CIBC FirstCaribbean, Scotiabank, or First Citizens","options":[{"label":"Republic Bank","value":"republic-bank"},{"label":"CIBC FirstCaribbean","value":"cibc-firstcaribbean"},{"label":"Scotiabank","value":"scotiabank"},{"label":"First Citizens","value":"first-citizens"},{"label":"Other","value":"other"}],"validations":{"required":{"value":true,"error":"Bank name is required"}}}},{"ref":"components/account-number","overrides":{"fieldId":"bank-account-number","label":"Account number","hint":"Enter the account number exactly as it appears on your bank statement","validations":{"required":{"value":true,"error":"Account number is required"}}}},{"ref":"components/name","overrides":{"fieldId":"bank-branch-name","label":"Branch name","hint":"Enter the branch where the account is held","validations":{"required":{"value":true,"error":"Branch name is required"}}}},{"ref":"components/name","overrides":{"fieldId":"bank-branch-code","label":"Branch code","hint":"Enter the bank branch code used for transfers","validations":{"required":{"value":true,"error":"Branch code is required"}}}},{"ref":"components/generic/radio","overrides":{"fieldId":"bank-account-type","label":"Account type","options":[{"label":"Savings","value":"savings"},{"label":"Chequing","value":"chequing"}],"validations":{"required":{"value":true,"error":"Please select an account type"}}}}]},{"stepId":"declaration","title":"Declaration","elements":[{"ref":"components/confirmation","overrides":{"fieldId":"declaration-confirmed","label":"Declaration","options":[{"label":"I confirm that my information is correct and I am happy for it to be verified. I understand that false details may lead to my application being rejected, and that the Government of Barbados will keep my information confidential.","value":"confirmed"}],"validations":{"required":{"value":true,"error":"You must confirm the declaration to continue"}}}},{"ref":"components/date-of-birth","overrides":{"fieldId":"declaration-date","label":"Date of declaration","isHidden":true}}]},{"stepId":"submission-confirmation","title":"Thank you for your request","elements":[],"nextSteps":[{"title":"What happens next","content":"Your application has been sent to the principal of the child''s school for review. The school will check that the child is eligible and no other claim has been submitted for the same child in this academic year. Once the principal approves the application, the payment details you provided will be added to the system. If approved, BDS $100 will be paid to the bank account you provided."}]}],"processors":[{"type":"email","config":{"recipientField":"applicant-details.applicant-email","subject":"Your textbook grant application has been received"}}]}', '2026-05-21 20:22:16.556', '2026-05-21 20:22:16.556', '2026-05-21 20:22:16.556'),
('db46e495-a54a-45e5-bbf9-62b0ff4cbb8d', 'request-a-presidential-visit-for-a-centenarian', '1.0.0', '{"formId":"request-a-presidential-visit-for-a-centenarian","title":"Request a Presidential Visit for a Centenarian","description":"Request a visit from the President of Barbados for someone turning or who has turned 100.","version":"1.0.0","createdAt":"2026-05-21T00:00:00Z","updatedAt":"2026-05-21T00:00:00Z","steps":[{"stepId":"centenarian-info","title":"Tell us about the centenarian","elements":[{"ref":"components/name","overrides":{"fieldId":"centenarian-full-name","label":"Full name","validations":{"required":{"value":true,"error":"Enter the centenarian''s full name"},"minLength":{"value":2,"error":"Full name must be at least 2 characters"}}}},{"ref":"components/date-of-birth","overrides":{"fieldId":"centenarian-dob","label":"Date of birth","validations":{"required":{"value":true,"error":"Enter the centenarian''s date of birth"}}}},{"ref":"components/sex","overrides":{"fieldId":"centenarian-sex","label":"What is the sex of the centenarian?","hint":"This determines which documents you need to upload.","validations":{"required":{"value":true,"error":"Choose male or female"}}}}]},{"stepId":"addresses","title":"Where does the centenarian live?","elements":[{"ref":"components/address","overrides":{"fieldId":"home-address-1","label":"Address line 1","validations":{"required":{"value":true,"error":"Enter the first line of the home address"},"minLength":{"value":2,"error":"Address must be at least 2 characters"}}}},{"ref":"components/address","overrides":{"fieldId":"home-address-2","label":"Address line 2 (optional)"}},{"ref":"components/parish","overrides":{"fieldId":"home-parish","options":[{"label":"Christ Church","value":"christ-church"},{"label":"St. Andrew","value":"st-andrew"},{"label":"St. George","value":"st-george"},{"label":"St. James","value":"st-james"},{"label":"St. John","value":"st-john"},{"label":"St. Joseph","value":"st-joseph"},{"label":"St. Lucy","value":"st-lucy"},{"label":"St. Michael","value":"st-michael"},{"label":"St. Peter","value":"st-peter"},{"label":"St. Philip","value":"st-philip"},{"label":"St. Thomas","value":"st-thomas"}],"validations":{"required":{"value":true,"error":"Choose a parish"}}}},{"ref":"components/generic/radio","overrides":{"fieldId":"visit-same-address","label":"Will the visit take place at this address?","options":[{"label":"Yes","value":"yes"},{"label":"No - the visit will be at a different address","value":"no"}],"validations":{"required":{"value":true,"error":"Choose where the visit will take place"}}}},{"ref":"components/address","overrides":{"fieldId":"visit-address-1","label":"Visit address line 1","behaviours":[{"type":"fieldConditionalOn","targetFieldId":"visit-same-address","operator":"equal","value":"no"}],"validations":{"required":{"value":true,"error":"Enter the first line of the visit address"}}}},{"ref":"components/address","overrides":{"fieldId":"visit-address-2","label":"Visit address line 2 (optional)","behaviours":[{"type":"fieldConditionalOn","targetFieldId":"visit-same-address","operator":"equal","value":"no"}]}},{"ref":"components/parish","overrides":{"fieldId":"visit-parish","options":[{"label":"Christ Church","value":"christ-church"},{"label":"St. Andrew","value":"st-andrew"},{"label":"St. George","value":"st-george"},{"label":"St. James","value":"st-james"},{"label":"St. John","value":"st-john"},{"label":"St. Joseph","value":"st-joseph"},{"label":"St. Lucy","value":"st-lucy"},{"label":"St. Michael","value":"st-michael"},{"label":"St. Peter","value":"st-peter"},{"label":"St. Philip","value":"st-philip"},{"label":"St. Thomas","value":"st-thomas"}],"behaviours":[{"type":"fieldConditionalOn","targetFieldId":"visit-same-address","operator":"equal","value":"no"}],"validations":{"required":{"value":true,"error":"Choose a parish for the visit address"}}}}]},{"stepId":"contact-person","title":"Who should we contact about the arrangements?","description":"Give us the details of the person the Office of the President should contact.","elements":[{"ref":"components/name","overrides":{"fieldId":"contact-full-name","label":"Full name","validations":{"required":{"value":true,"error":"Enter the contact person''s full name"},"minLength":{"value":2,"error":"Full name must be at least 2 characters"}}}},{"ref":"components/address","overrides":{"fieldId":"contact-address-1","label":"Address line 1","validations":{"required":{"value":true,"error":"Enter the contact person''s address"},"minLength":{"value":2,"error":"Address must be at least 2 characters"}}}},{"ref":"components/address","overrides":{"fieldId":"contact-address-2","label":"Address line 2 (optional)"}},{"ref":"components/parish","overrides":{"fieldId":"contact-parish","options":[{"label":"Christ Church","value":"christ-church"},{"label":"St. Andrew","value":"st-andrew"},{"label":"St. George","value":"st-george"},{"label":"St. James","value":"st-james"},{"label":"St. John","value":"st-john"},{"label":"St. Joseph","value":"st-joseph"},{"label":"St. Lucy","value":"st-lucy"},{"label":"St. Michael","value":"st-michael"},{"label":"St. Peter","value":"st-peter"},{"label":"St. Philip","value":"st-philip"},{"label":"St. Thomas","value":"st-thomas"}],"validations":{"required":{"value":true,"error":"Choose a parish"}}}},{"ref":"components/telephone","overrides":{"fieldId":"contact-phone","label":"Phone number","hint":"For example, 246-555-1234","validations":{"required":{"value":true,"error":"Enter a phone number"}}}},{"ref":"components/email","overrides":{"fieldId":"contact-email","label":"Email address","hint":"We''ll send you a confirmation of your request.","validations":{"required":{"value":true,"error":"Enter your email address"}}}}]},{"stepId":"upload-documents","title":"Upload your documents","description":"Upload a scan or clear photo. Accepted formats: PDF, JPG, PNG. Max 5MB per file.","elements":[{"ref":"components/upload-document","overrides":{"fieldId":"birth-certificate","label":"Birth certificate","hint":"Original birth certificate with names included. Required for all centenarians.","validations":{"required":{"value":true,"error":"Upload the birth certificate"}}}},{"ref":"components/upload-document","overrides":{"fieldId":"marriage-certificate","label":"Marriage certificate(s)","hint":"Upload if she is or has been married.","multiple":true,"behaviours":[{"type":"fieldConditionalOn","targetFieldId":"centenarian-sex","operator":"equal","value":"female"}]}}]},{"stepId":"declaration","title":"Declaration","elements":[{"ref":"components/confirmation","overrides":{"fieldId":"declaration-confirmed","label":"Declaration","options":[{"label":"I confirm that the information I have given is correct to the best of my knowledge, that the request will be received at least 3 months before the birthday, and that the documents I have uploaded are true copies of the originals.","value":"confirmed"}],"validations":{"required":{"value":true,"error":"You must confirm the declaration to continue"}}}},{"ref":"components/date-of-birth","overrides":{"fieldId":"declaration-date","label":"Date of declaration","isHidden":true}}]},{"stepId":"submission-confirmation","title":"Request submitted","elements":[],"nextSteps":[{"title":"What happens next","content":"The Office of the President will review your request and contact the person you named to discuss the arrangements. If you don''t hear back within 4 weeks, contact the Office of the President directly at State House, Government Hill, St Michael."}]}],"processors":[{"type":"email","config":{"recipientField":"contact-person.contact-email","subject":"Your presidential visit request has been received"}}]}', '2026-05-21 20:22:16.556', '2026-05-21 20:22:16.556', '2026-05-21 20:22:16.556');
